#include <stdio.h>
#define READ  4
#define WRITE 2
#define EXEC  1
int set_flag(int flags, int bit) {
    return flags | bit;
}
int clear_flag(int flags, int bit) {
    return flags & ~bit;
}
int has_flag(int flags, int bit) {
    return (flags & bit) != 0;
}

int main(void) {
    {
        printf("%d\n", (int)(set_flag(0, READ | WRITE)));
        printf("%d\n", (int)(set_flag(6, EXEC)));
        printf("%d\n", (int)(set_flag(5, READ)));
        printf("%d\n", (int)(set_flag(7, EXEC)));
    }
    {
        printf("%d\n", (int)(clear_flag(7, WRITE)));
        printf("%d\n", (int)(clear_flag(7, READ | WRITE)));
        printf("%d\n", (int)(clear_flag(7, READ | WRITE | EXEC)));
        printf("%d\n", (int)(clear_flag(6, WRITE)));
    }
    {
        printf("%d\n", (int)(has_flag(7, READ)));
        printf("%d\n", (int)(has_flag(7, WRITE)));
        printf("%d\n", (int)(has_flag(7, EXEC)));
        printf("%d\n", (int)(has_flag(1, WRITE)));
    }
    return 0;
}

